import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import styles from '../css/Search.module.css';

function SearchBar({ onSearchResults }) {
  const [keyword, setKeyword] = useState('');
  const [suggestions, setSuggestions] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);

  const handleSearch = async (e) => {
    e.preventDefault();
    if (!keyword.trim()) return;

    try {
      const userId = sessionStorage.getItem('user_id') || '';
      const res = await axios.get('/search', {
        params: { keyword, userId }
      });
      if (onSearchResults) {
        onSearchResults(res.data);
      }
    } catch (error) {
      console.error('검색 실패:', error);
    }
    setShowSuggestions(false);
  };

  const handleChange = async (e) => {
    const value = e.target.value;
    setKeyword(value);

    if (value.trim().length >= 1) {
      try {
        const res = await axios.get('/search', {
          params: { keyword: value, userId: sessionStorage.getItem('user_id') || '' }
        });
        setSuggestions(res.data.slice(0, 5));
        setShowSuggestions(true);
      } catch {
        setSuggestions([]);
      }
    } else {
      setSuggestions([]);
      setShowSuggestions(false);
    }
  };

  const handleSuggestionClick = (title) => {
    setKeyword(title);
    setShowSuggestions(false);
    // 자동 검색
    axios.get('/search', {
      params: { keyword: title, userId: sessionStorage.getItem('user_id') || '' }
    }).then(res => {
      if (onSearchResults) onSearchResults(res.data);
    });
  };

  return (
    <div className={styles.searchContainer}>
      <form onSubmit={handleSearch} className={styles.searchForm}>
        <input
          type="text"
          value={keyword}
          onChange={handleChange}
          placeholder="공구 검색..."
          className={styles.searchInput}
          onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
          onFocus={() => suggestions.length > 0 && setShowSuggestions(true)}
        />
        <button type="submit" className={styles.searchButton}>검색</button>
      </form>
      {showSuggestions && suggestions.length > 0 && (
        <ul className={styles.suggestions}>
          {suggestions.map((item, idx) => (
            <li key={idx} onClick={() => handleSuggestionClick(item.title)}
                className={styles.suggestionItem}>
              {item.title}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default SearchBar;
